platform_context.structure:
AQPlatformContext {
  // Sandbox Plane
  sandboxProvider: ISandboxProvider

  // Tool Plane
  toolRegistry: IAQToolRegistrySimple
  toolRuntimeExecutor: IToolRuntimeExecutor
  toolRepository: IToolRepository
  toolHandlerRegistry: IToolHandlerRegistry
  toolExecutorFactory: IToolExecutorFactory

  // Subject Plane
  subjectRegistry: IAQSubjectRegistry
  subjectSessionFactory: ISubjectSessionFactory
  subjectRepository: ISubjectRepository
  subjectSessionRepository: ISubjectSessionRepository
  subjectExecutorRegistry: ISubjectExecutorRegistry
}
